\begin {aligned}
I & \colon { \mathopen {} \left  [ m \right  ] \mathclose {}} \times { \mathopen {} \left  [ n \right  ] \mathclose {}} \to   { \mathopen {} \left  [ m \cdot  n \right  ] \mathclose {}} \\ 
I { \mathopen {} \left ( i,j \right ) \mathclose {}}  &= m \cdot  j + i
\end {aligned}

\begin {aligned}
I & \colon { \mathopen {} \left  [ m \right  ] \mathclose {}} + { \mathopen {} \left  [ n \right  ] \mathclose {}}   \to   { \mathopen {} \left  [ m+n \right  ] \mathclose {}} \\ 
I { \mathopen {} \left ( 0,i<m \right ) \mathclose {}}  &= i \\ 
I { \mathopen {} \left ( 1,j<n \right ) \mathclose {}}  &= m+j
\end {aligned}

I { \mathopen {} \left ( k \right ) \mathclose {}}  =
 \begin {cases}
  { \mathopen {} \left ( 0,k \right ) \mathclose {}}  & \text {when } k < m \\ 
  { \mathopen {} \left ( 1,k-m \right ) \mathclose {}}  & \text {when } k  \geq  m
 \end {cases}

